input.content:
{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "平安扣 Pinankou",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home",
      "name": "首页/工作台",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-add-button",
          "role": "action",
          "event": "open-add-sheet"
        },
        {
          "id": "home-search-button",
          "role": "action",
          "event": "open-search"
        },
        {
          "id": "home-statistics-link",
          "role": "action",
          "event": "navigate-statistics"
        },
        {
          "id": "home-todo-list",
          "role": "list",
          "binding": "/todos",
          "itemIdPattern": "home-todo-{id}",
          "emptyStateId": "home-todo-empty"
        },
        {
          "id": "home-quick-record",
          "role": "action",
          "event": "navigate-record-form"
        },
        {
          "id": "home-quick-hazard",
          "role": "action",
          "event": "navigate-hazard-form"
        },
        {
          "id": "home-quick-patrol",
          "role": "action",
          "event": "navigate-patrols"
        },
        {
          "id": "home-recent-list",
          "role": "list",
          "binding": "/recentActivities",
          "itemIdPattern": "home-recent-{id}",
          "emptyStateId": "home-recent-empty"
        }
      ]
    },
    {
      "id": "records-page",
      "surfaceId": "records",
      "pageId": "records",
      "name": "安全事项",
      "route": "pages/Records",
      "tabId": "tab-records",
      "semanticTargets": [
        {
          "id": "records-add-button",
          "role": "action",
          "event": "navigate-record-form"
        },
        {
          "id": "records-search-input",
          "role": "input",
          "binding": "/records/filter/keyword"
        },
        {
          "id": "records-filter-category",
          "role": "input",
          "binding": "/records/filter/category"
        },
        {
          "id": "records-list",
          "role": "list",
          "binding": "/records",
          "itemIdPattern": "records-item-{id}",
          "emptyStateId": "records-empty"
        },
        {
          "id": "records-loading",
          "role": "assertion",
          "binding": "/records/loading"
        }
      ]
    },
    {
      "id": "record-form-page",
      "surfaceId": "record-form",
      "pageId": "record-form",
      "name": "安全事项表单",
      "route": "pages/RecordForm",
      "semanticTargets": [
        {
          "id": "record-form-title-input",
          "role": "input",
          "binding": "/recordForm/title"
        },
        {
          "id": "record-form-category-picker",
          "role": "input",
          "binding": "/recordForm/category"
        },
        {
          "id": "record-form-priority-picker",
          "role": "input",
          "binding": "/recordForm/priority"
        },
        {
          "id": "record-form-description-input",
          "role": "input",
          "binding": "/recordForm/description"
        },
        {
          "id": "record-form-photo-uploader",
          "role": "input",
          "binding": "/recordForm/photos"
        },
        {
          "id": "record-form-save-button",
          "role": "action",
          "event": "save-record"
        },
        {
          "id": "record-form-cancel-button",
          "role": "action",
          "event": "cancel-record-form"
        }
      ]
    },
    {
      "id": "record-detail-page",
      "surfaceId": "record-detail",
      "pageId": "record-detail",
      "name": "安全事项详情",
      "route": "pages/RecordDetail",
      "semanticTargets": [
        {
          "id": "record-detail-edit-button",
          "role": "action",
          "event": "navigate-record-form"
        },
        {
          "id": "record-detail-delete-button",
          "role": "action",
          "event": "delete-record"
        },
        {
          "id": "record-detail-status-badge",
          "role": "assertion",
          "binding": "/recordDetail/status"
        },
        {
          "id": "record-detail-photos",
          "role": "list",
          "binding": "/recordDetail/photos",
          "itemIdPattern": "record-photo-{index}"
        }
      ]
    },
    {
      "id": "hazards-page",
      "surfaceId": "hazards",
      "pageId": "hazards",
      "name": "风险隐患",
      "route": "pages/Hazards",
      "tabId": "tab-hazards",
      "semanticTargets": [
        {
          "id": "hazards-add-button",
          "role": "action",
          "event": "navigate-hazard-form"
        },
        {
          "id": "hazards-search-input",
          "role": "input",
          "binding": "/hazards/filter/keyword"
        },
        {
          "id": "hazards-status-filter",
          "role": "input",
          "binding": "/hazards/filter/status"
        },
        {
          "id": "hazards-list",
          "role": "list",
          "binding": "/hazards",
          "itemIdPattern": "hazards-item-{id}",
          "emptyStateId": "hazards-empty"
        },
        {
          "id": "hazards-level-filter",
          "role": "input",
          "binding": "/hazards/filter/level"
        }
      ]
    },
    {
      "id": "hazard-form-page",
      "surfaceId": "hazard-form",
      "pageId": "hazard-form",
      "name": "风险隐患上报",
      "route": "pages/HazardForm",
      "semanticTargets": [
        {
          "id": "hazard-form-title-input",
          "role": "input",
          "binding": "/hazardForm/title"
        },
        {
          "id": "hazard-form-location-input",
          "role": "input",
          "binding": "/hazardForm/location"
        },
        {
          "id": "hazard-form-level-picker",
          "role": "input",
          "binding": "/hazardForm/level"
        },
        {
          "id": "hazard-form-description-input",
          "role": "input",
          "binding": "/hazardForm/description"
        },
        {
          "id": "hazard-form-photo-uploader",
          "role": "input",
          "binding": "/hazardForm/photos"
        },
        {
          "id": "hazard-form-submit-button",
          "role": "action",
          "event": "submit-hazard"
        }
      ]
    },
    {
      "id": "hazard-detail-page",
      "surfaceId": "hazard-detail",
      "pageId": "hazard-detail",
      "name": "风险隐患详情",
      "route": "pages/HazardDetail",
      "semanticTargets": [
        {
          "id": "hazard-detail-level-badge",
          "role": "assertion",
          "binding": "/hazardDetail/level"
        },
        {
          "id": "hazard-detail-status-badge",
          "role": "assertion",
          "binding": "/hazardDetail/status"
        },
        {
          "id": "hazard-detail-correct-button",
          "role": "action",
          "event": "start-correction"
        },
        {
          "id": "hazard-detail-photos",
          "role": "list",
          "binding": "/hazardDetail/photos",
          "itemIdPattern": "hazard-photo-{index}"
        }
      ]
    },
    {
      "id": "patrols-page",
      "surfaceId": "patrols",
      "pageId": "patrols",
      "name": "巡检打卡",
      "route": "pages/Patrols",
      "tabId": "tab-patrols",
      "semanticTargets": [
        {
          "id": "patrols-checkin-button",
          "role": "action",
          "event": "navigate-patrol-checkin"
        },
        {
          "id": "patrols-date-filter",
          "role": "input",
          "binding": "/patrols/filter/date"
        },
        {
          "id": "patrols-list",
          "role": "list",
          "binding": "/patrols",
          "itemIdPattern": "patrols-item-{id}",
          "emptyStateId": "patrols-empty"
        },
        {
          "id": "patrols-progress-ring",
          "role": "assertion",
          "binding": "/patrols/completionRate"
        }
      ]
    },
    {
      "id": "patrol-checkin-page",
      "surfaceId": "patrol-checkin",
      "pageId": "patrol-checkin",
      "name": "巡检打卡确认",
      "route": "pages/PatrolCheckin",
      "semanticTargets": [
        {
          "id": "patrol-checkin-point-picker",
          "role": "input",
          "binding": "/patrolCheckin/pointId"
        },
        {
          "id": "patrol-checkin-photo-uploader",
          "role": "input",
          "binding": "/patrolCheckin/photos"
        },
        {
          "id": "patrol-checkin-note-input",
          "role": "input",
          "binding": "/patrolCheckin/note"
        },
        {
          "id": "patrol-checkin-confirm-button",
          "role": "action",
          "event": "confirm-patrol-checkin"
        }
      ]
    },
    {
      "id": "contacts-page",
      "surfaceId": "contacts",
      "pageId": "contacts",
      "name": "应急联系人",
      "route": "pages/Contacts",
      "semanticTargets": [
        {
          "id": "contacts-add-button",
          "role": "action",
          "event": "navigate-contact-form"
        },
        {
          "id": "contacts-search-input",
          "role": "input",
          "binding": "/contacts/filter/keyword"
        },
        {
          "id": "contacts-group-filter",
          "role": "input",
          "binding": "/contacts/filter/group"
        },
        {
          "id": "contacts-list",
          "role": "list",
          "binding": "/contacts",
          "itemIdPattern": "contacts-item-{id}",
          "emptyStateId": "contacts-empty"
        }
      ]
    },
    {
      "id": "contact-detail-page",
      "surfaceId": "contact-detail",
      "pageId": "contact-detail",
      "name": "联系人详情",
      "route": "pages/ContactDetail",
      "semanticTargets": [
        {
          "id": "contact-detail-call-button",
          "role": "action",
          "event": "call-contact"
        },
        {
          "id": "contact-detail-edit-button",
          "role": "action",
          "event": "navigate-contact-form"
        },
        {
          "id": "contact-detail-delete-button",
          "role": "action",
          "event": "delete-contact"
        }
      ]
    },
    {
      "id": "corrections-page",
      "surfaceId": "corrections",
      "pageId": "corrections",
      "name": "整改进度",
      "route": "pages/Corrections",
      "semanticTargets": [
        {
          "id": "corrections-add-button",
          "role": "action",
          "event": "navigate-correction-form"
        },
        {
          "id": "corrections-status-filter",
          "role": "input",
          "binding": "/corrections/filter/status"
        },
        {
          "id": "corrections-list",
          "role": "list",
          "binding": "/corrections",
          "itemIdPattern": "corrections-item-{id}",
          "emptyStateId": "corrections-empty"
        },
        {
          "id": "corrections-overdue-count",
          "role": "assertion",
          "binding": "/corrections/overdueCount"
        }
      ]
    },
    {
      "id": "correction-form-page",
      "surfaceId": "correction-form",
      "pageId": "correction-form",
      "name": "整改进度更新",
      "route": "pages/CorrectionForm",
      "semanticTargets": [
        {
          "id": "correction-form-status-picker",
          "role": "input",
          "binding": "/correctionForm/status"
        },
        {
          "id": "correction-form-progress-slider",
          "role": "input",
          "binding": "/correctionForm/progress"
        },
        {
          "id": "correction-form-note-input",
          "role": "input",
          "binding": "/correctionForm/note"
        },
        {
          "id": "correction-form-photo-uploader",
          "role": "input",
          "binding": "/correctionForm/photos"
        },
        {
          "id": "correction-form-save-button",
          "role": "action",
          "event": "save-correction"
        }
      ]
    },
    {
      "id": "correction-detail-page",
      "surfaceId": "correction-detail",
      "pageId": "correction-detail",
      "name": "整改详情",
      "route": "pages/CorrectionDetail",
      "semanticTargets": [
        {
          "id": "correction-detail-progress-bar",
          "role": "assertion",
          "binding": "/correctionDetail/progress"
        },
        {
          "id": "correction-detail-status-badge",
          "role": "assertion",
          "binding": "/correctionDetail/status"
        },
        {
          "id": "correction-detail-update-button",
          "role": "action",
          "event": "navigate-correction-form"
        }
      ]
    },
    {
      "id": "statistics-page",
      "surfaceId": "statistics",
      "pageId": "statistics",
      "name": "统计看板",
      "route": "pages/Statistics",
      "semanticTargets": [
        {
          "id": "statistics-period-picker",
          "role": "input",
          "binding": "/statistics/period"
        },
        {
          "id": "statistics-hazard-total",
          "role": "assertion",
          "binding": "/statistics/hazardTotal"
        },
        {
          "id": "statistics-correction-rate",
          "role": "assertion",
          "binding": "/statistics/correctionRate"
        },
        {
          "id": "statistics-patrol-completion",
          "role": "assertion",
          "binding": "/statistics/patrolCompletion"
        },
        {
          "id": "statistics-overdue-count",
          "role": "assertion",
          "binding": "/statistics/overdueCount"
        },
        {
          "id": "statistics-trend-chart",
          "role": "assertion",
          "binding": "/statistics/trendData"
        }
      ]
    },
    {
      "id": "profile-page",
      "surfaceId": "profile",
      "pageId": "profile",
      "name": "我的",
      "route": "pages/Profile",
      "tabId": "tab-profile",
      "semanticTargets": [
        {
          "id": "profile-contacts-link",
          "role": "action",
          "event": "navigate-contacts"
        },
        {
          "id": "profile-corrections-link",
          "role": "action",
          "event": "navigate-corrections"
        },
        {
          "id": "profile-statistics-link",
          "role": "action",
          "event": "navigate-statistics"
        },
        {
          "id": "profile-settings-link",
          "role": "action",
          "event": "navigate-settings"
        }
      ]
    }
  ],
  "events": [
    { "name": "open-add-sheet", "description": "打开快捷新增菜单" },
    { "name": "open-search", "description": "打开全局搜索" },
    { "name": "navigate-statistics", "description": "跳转到统计看板" },
    { "name": "navigate-record-form", "description": "跳转到安全事项表单" },
    { "name": "navigate-hazard-form", "description": "跳转到隐患上报表单" },
    { "name": "navigate-patrols", "description": "跳转到巡检页面" },
    { "name": "save-record", "description": "保存安全事项" },
    { "name": "cancel-record-form", "description": "取消安全事项表单" },
    { "name": "delete-record", "description": "删除安全事项" },
    { "name": "submit-hazard", "description": "提交风险隐患" },
    { "name": "start-correction", "description": "对隐患发起整改" },
    { "name": "navigate-patrol-checkin", "description": "跳转到巡检打卡" },
    { "name": "confirm-patrol-checkin", "description": "确认巡检打卡" },
    { "name": "navigate-contact-form", "description": "跳转到联系人表单" },
    { "name": "call-contact", "description": "拨打联系人电话" },
    { "name": "delete-contact", "description": "删除联系人" },
    { "name": "navigate-correction-form", "description": "跳转到整改表单" },
    { "name": "save-correction", "description": "保存整改进度" },
    { "name": "navigate-contacts", "description": "跳转到应急联系人" },
    { "name": "navigate-corrections", "description": "跳转到整改进度" },
    { "name": "navigate-settings", "description": "跳转到设置" }
  ],
  "bindings": {
    "/todos": { "type": "array", "description": "首页待办列表" },
    "/recentActivities": { "type": "array", "description": "首页最近动态" },
    "/records": { "type": "array", "description": "安全事项列表" },
    "/records/filter/keyword": { "type": "string", "description": "安全事项搜索关键词" },
    "/records/filter/category": { "type": "string", "description": "安全事项分类筛选" },
    "/recordForm/title": { "type": "string", "description": "事项标题" },
    "/recordForm/category": { "type": "string", "description": "事项分类" },
    "/recordForm/priority": { "type": "string", "description": "事项优先级" },
    "/recordForm/description": { "type": "string", "description": "事项描述" },
    "/recordForm/photos": { "type": "array", "description": "事项照片" },
    "/recordDetail/status": { "type": "string", "description": "事项状态" },
    "/recordDetail/photos": { "type": "array", "description": "事项详情照片" },
    "/hazards": { "type": "array", "description": "隐患列表" },
    "/hazards/filter/keyword": { "type": "string", "description": "隐患搜索关键词" },
    "/hazards/filter/status": { "type": "string", "description": "隐患状态筛选" },
    "/hazards/filter/level": { "type": "string", "description": "隐患等级筛选" },
    "/hazardForm/title": { "type": "string", "description": "隐患标题" },
    "/hazardForm/location": { "type": "string", "description": "隐患位置" },
    "/hazardForm/level": { "type": "string", "description": "隐患等级" },
    "/hazardForm/description": { "type": "string", "description": "隐患描述" },
    "/hazardForm/photos": { "type": "array", "description": "隐患照片" },
    "/hazardDetail/level": { "type": "string", "description": "隐患等级" },
    "/hazardDetail/status": { "type": "string", "description": "隐患状态" },
    "/hazardDetail/photos": { "type": "array", "description": "隐患详情照片" },
    "/patrols": { "type": "array", "description": "巡检记录列表" },
    "/patrols/filter/date": { "type": "string", "description": "巡检日期筛选" },
    "/patrols/completionRate": { "type": "number", "description": "巡检完成率" },
    "/patrolCheckin/pointId": { "type": "string", "description": "巡检点 ID" },
    "/patrolCheckin/photos": { "type": "array", "description": "巡检打卡照片" },
    "/patrolCheckin/note": { "type": "string", "description": "巡检备注" },
    "/contacts": { "type": "array", "description": "联系人列表" },
    "/contacts/filter/keyword": { "type": "string", "description": "联系人搜索关键词" },
    "/contacts/filter/group": { "type": "string", "description": "联系人分组筛选" },
    "/corrections": { "type": "array", "description": "整改任务列表" },
    "/corrections/filter/status": { "type": "string", "description": "整改状态筛选" },
    "/corrections/overdueCount": { "type": "number", "description": "逾期整改数量" },
    "/correctionForm/status": { "type": "string", "description": "整改状态" },
