    "/correctionDetail/status": { "type": "string", "description": "整改详情状态" },
    "/statistics/period": { "type": "string", "description": "统计周期" },
    "/statistics/hazardTotal": { "type": "number", "description": "隐患总数" },
    "/statistics/correctionRate": { "type": "number", "description": "整改率" },
    "/statistics/patrolCompletion": { "type": "number", "description": "巡检完成率" },
    "/statistics/overdueCount": { "type": "number", "description": "逾期任务数" },
    "/statistics/trendData": { "type": "array", "description": "趋势图数据" }
  },
  "testTargets": [
    "home-add-button",
    "home-todo-list",
    "home-recent-list",
    "home-statistics-link",
    "records-add-button",
    "records-list",
