    "patrol-checkin-confirm-button",
    "contacts-add-button",
    "contacts-list",
    "contact-detail-call-button",
    "corrections-add-button",
    "corrections-list",
    "correction-form-save-button",
    "statistics-hazard-total",
    "statistics-correction-rate",
    "profile-contacts-link",
    "profile-corrections-link",
    "bottom-tab-home",
    "bottom-tab-records",
    "bottom-tab-hazards",
    "bottom-tab-patrols",
    "bottom-tab-profile"
